import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { forkJoin, of } from 'rxjs';
import { catchError } from 'rxjs/operators';
import { ResumeEditorResume, ResumeTemplate, UsageLimit } from '../../../core/models/resume.model';
import { ResumeService } from '../../../core/services/resume.service';

@Component({
  selector: 'app-my-resumes',
  templateUrl: './my-resumes.component.html'
})
export class MyResumesComponent implements OnInit {
  loading = true;
  error = '';
  showUpgradeModal = false;
  showStartModal = false;
  importing = false;
  activeMenuResumeId: number | null = null;

  resumes: ResumeEditorResume[] = [];
  usageLimit: UsageLimit | null = null;
  templateMap = new Map<number, ResumeTemplate>();

  constructor(
    private readonly resumeService: ResumeService,
    private readonly router: Router
  ) {
  }

  ngOnInit(): void {
    forkJoin({
      resumes: this.resumeService.getEditorResumes(),
      usageLimit: this.resumeService.getUsageLimit().pipe(catchError(() => of(null))),
      templates: this.resumeService.getTemplates().pipe(catchError(() => of([])))
    }).subscribe({
      next: ({ resumes, usageLimit, templates }) => {
        this.resumes = resumes;
        this.usageLimit = usageLimit;
        this.templateMap = new Map(templates.map((template) => [template.id, template]));
        this.loading = false;
      },
      error: () => {
        this.error = 'Unable to load resumes right now.';
        this.loading = false;
      }
    });
  }

  get isFreePlan(): boolean {
    return !this.usageLimit?.premium;
  }

  onCreateResume(): void {
    if (this.isFreePlan && this.resumes.length >= 1) {
      this.showUpgradeModal = true;
      return;
    }
    this.showStartModal = true;
  }

  startFromTemplate(): void {
    this.showStartModal = false;
    void this.router.navigate(['/templates']);
  }

  onImportResume(event: Event): void {
    const input = event.target as HTMLInputElement;
    const file = input.files?.[0];
    if (!file) {
      return;
    }
    this.importing = true;
    this.resumeService.importResume(file).subscribe({
      next: ({ resumeId }) => {
        this.importing = false;
        this.showStartModal = false;
        void this.router.navigate(['/resume-editor', resumeId, 'content']);
      },
      error: (error) => {
        this.importing = false;
        this.error = error?.error?.message ?? 'Unable to import resume.';
      }
    });
    input.value = '';
  }

  onDuplicate(resume: ResumeEditorResume): void {
    if (this.isFreePlan && this.resumes.length >= 1) {
      this.showUpgradeModal = true;
      this.activeMenuResumeId = null;
      return;
    }

    this.resumeService.duplicateEditorResume(resume.id).subscribe({
      next: (copy) => {
        this.resumes = [copy, ...this.resumes];
        this.activeMenuResumeId = null;
      },
      error: (error) => {
        this.error = error?.error?.message ?? 'Unable to duplicate resume.';
      }
    });
  }

  onDelete(resume: ResumeEditorResume): void {
    if (!confirm(`Delete ${resume.title}?`)) {
      return;
    }
    this.resumeService.deleteEditorResume(resume.id).subscribe({
      next: () => {
        this.resumes = this.resumes.filter((item) => item.id !== resume.id);
        this.activeMenuResumeId = null;
      },
      error: () => this.error = 'Unable to delete resume.'
    });
  }

  onRename(resume: ResumeEditorResume): void {
    const title = prompt('Rename resume', resume.title)?.trim();
    if (!title || title === resume.title) {
      this.activeMenuResumeId = null;
      return;
    }
    this.resumeService.updateEditorResume(resume.id, { templateId: resume.templateId, title }).subscribe({
      next: (updated) => {
        this.resumes = this.resumes.map((item) => item.id === resume.id ? updated : item);
        this.activeMenuResumeId = null;
      },
      error: () => this.error = 'Unable to rename resume.'
    });
  }

  downloadResume(resume: ResumeEditorResume): void {
    const blob = new Blob([resume.generatedHtml], { type: 'text/html;charset=utf-8' });
    const objectUrl = URL.createObjectURL(blob);
    const anchor = document.createElement('a');
    anchor.href = objectUrl;
    anchor.download = `${resume.title.replace(/[^a-z0-9]+/gi, '-').toLowerCase() || 'resume'}.html`;
    anchor.click();
    URL.revokeObjectURL(objectUrl);
    this.activeMenuResumeId = null;
  }

  openResume(resumeId: number, tab: 'overview' | 'content' | 'customize' | 'ai' = 'content'): void {
    this.activeMenuResumeId = null;
    const mappedTab = tab === 'ai' ? 'ai-tools' : tab;
    void this.router.navigate(['/resume-editor', resumeId, mappedTab]);
  }

  goToPlans(): void {
    this.showUpgradeModal = false;
    void this.router.navigate(['/pricing']);
  }

  templateName(resume: ResumeEditorResume): string {
    return this.templateMap.get(resume.templateId)?.name || resume.templateName;
  }

  lastEdited(resume: ResumeEditorResume): string {
    return new Date(resume.updatedAt).toLocaleDateString();
  }
}
<app-loader *ngIf="loading" message="Loading your resumes"></app-loader>

<div *ngIf="!loading" class="space-y-6">
  <header>
    <h1 class="section-title text-3xl text-[#17172b]">My Resumes</h1>
    <p class="mt-2 text-sm text-[#667085]">Your first resume is free forever. Need more than one resume? <a routerLink="/pricing" class="font-semibold text-[#5b5cf0]">Upgrade your plan.</a></p>
  </header>

  <p *ngIf="error" class="rounded-2xl bg-[#fff1f1] px-4 py-3 text-sm font-medium text-[#ef4444]">{{ error }}</p>

  <section *ngIf="resumes.length === 0" class="shell-card p-8 text-center">
    <h3 class="text-2xl font-extrabold text-[#17172b]">No resumes yet</h3>
    <p class="mt-2 text-sm text-[#667085]">Create your first ATS-friendly resume.</p>
    <div class="mt-5 flex flex-wrap justify-center gap-3">
      <button class="btn-primary" type="button" (click)="onCreateResume()">Create Resume</button>
      <a routerLink="/templates" class="btn-secondary">Browse Templates</a>
    </div>
  </section>

  <section class="grid gap-4 sm:grid-cols-2 xl:grid-cols-3">
    <article class="flex min-h-[320px] cursor-pointer flex-col items-center justify-center rounded-3xl border-2 border-dashed border-[#c8c5ff] bg-[#faf9ff] text-center" (click)="onCreateResume()">
      <div class="mb-5 flex h-16 w-16 items-center justify-center rounded-full bg-[#f0edff] text-4xl text-[#5b5cf0]">+</div>
      <h3 class="text-2xl font-extrabold text-[#17172b]">New Resume</h3>
      <p class="mt-2 text-sm text-[#667085]">Create from templates or import existing resume</p>
    </article>

    <article *ngFor="let resume of resumes" class="group relative overflow-hidden rounded-3xl border border-[#e5e7eb] bg-white p-4">
      <div class="h-[190px] overflow-hidden rounded-2xl border border-[#eceef8] bg-[#f8f9ff]">
        <div class="h-full w-full scale-[0.98] overflow-hidden" [innerHTML]="resume.generatedHtml"></div>
      </div>

      <div class="mt-4 flex items-start justify-between gap-3">
        <div>
          <h3 class="text-lg font-bold text-[#17172b]">{{ resume.title }}</h3>
          <p class="mt-1 text-xs text-[#667085]">Edited {{ lastEdited(resume) }} • {{ templateName(resume) }} • A4</p>
        </div>
        <button type="button" class="rounded-xl border px-2 py-1" (click)="activeMenuResumeId = activeMenuResumeId === resume.id ? null : resume.id">⋮</button>
      </div>

      <div *ngIf="activeMenuResumeId === resume.id" class="absolute right-4 top-[250px] z-20 w-52 rounded-2xl border border-[#eceef8] bg-white p-2 shadow-lg">
        <button class="menu-item" type="button" (click)="openResume(resume.id, 'content')">Edit</button>
        <button class="menu-item" type="button" (click)="onRename(resume)">Rename</button>
        <button class="menu-item" type="button" (click)="onDuplicate(resume)">Duplicate</button>
        <button class="menu-item" type="button" (click)="openResume(resume.id, 'customize')">Change Template</button>
        <button class="menu-item" type="button" (click)="openResume(resume.id, 'overview')">View Resume</button>
        <button class="menu-item" type="button" (click)="downloadResume(resume)">Download PDF</button>
        <button class="menu-item text-[#dc2626]" type="button" (click)="onDelete(resume)">Delete</button>
      </div>

      <div class="absolute inset-0 hidden items-end justify-center bg-[#0f172a]/45 p-4 text-white group-hover:flex">
        <div class="flex flex-wrap justify-center gap-2">
          <button class="rounded-xl bg-white px-3 py-2 text-sm font-semibold text-[#17172b]" (click)="openResume(resume.id, 'overview')">View Resume</button>
          <button class="rounded-xl bg-white px-3 py-2 text-sm font-semibold text-[#17172b]" (click)="openResume(resume.id, 'content')">Edit Resume</button>
          <button class="rounded-xl bg-white px-3 py-2 text-sm font-semibold text-[#17172b]" (click)="onDuplicate(resume)">Duplicate</button>
          <button class="rounded-xl bg-white px-3 py-2 text-sm font-semibold text-[#17172b]" (click)="openResume(resume.id, 'customize')">Change Template</button>
          <button class="rounded-xl bg-white px-3 py-2 text-sm font-semibold text-[#17172b]" (click)="downloadResume(resume)">Download PDF</button>
          <button class="rounded-xl bg-[#ef4444] px-3 py-2 text-sm font-semibold text-white" (click)="onDelete(resume)">Delete</button>
        </div>
      </div>
    </article>
  </section>
</div>

<div *ngIf="showUpgradeModal" class="fixed inset-0 z-50 flex items-center justify-center bg-[#0f172a]/60 p-4">
  <div class="w-full max-w-xl rounded-3xl bg-white p-8">
    <button class="ml-auto block text-2xl text-[#667085]" type="button" (click)="showUpgradeModal = false">×</button>
    <h3 class="mt-2 text-center text-3xl font-extrabold text-[#17172b]">Need more than one resume?</h3>
    <p class="mx-auto mt-3 max-w-md text-center text-[#667085]">Your free plan includes only one resume. Upgrade to create another.</p>
    <div class="mt-8 grid gap-3">
      <button class="btn-primary" type="button" (click)="goToPlans()">View Plans</button>
      <button class="btn-secondary" type="button" (click)="showUpgradeModal = false">Cancel</button>
    </div>
  </div>
</div>


<div *ngIf="showStartModal" class="fixed inset-0 z-50 flex items-center justify-center bg-[#0f172a]/60 p-4">
  <div class="w-full max-w-xl rounded-3xl bg-white p-8">
    <button class="ml-auto block text-2xl text-[#667085]" type="button" (click)="showStartModal = false">×</button>
    <h3 class="mt-2 text-center text-3xl font-extrabold text-[#17172b]">Start building your resume</h3>
    <p class="mx-auto mt-3 max-w-md text-center text-[#667085]">Choose how you want to begin.</p>
    <div class="mt-8 grid gap-3">
      <label class="btn-secondary cursor-pointer text-center">
        <input type="file" class="hidden" accept=".pdf,.doc,.docx" (change)="onImportResume($event)">
        {{ importing ? 'Importing...' : 'Import existing resume' }}
      </label>
      <button class="btn-primary" type="button" (click)="startFromTemplate()">Start from template</button>
    </div>
  </div>
</div>
